import React from 'react';
import { TopNav } from '../TopNav';
import { ChevronLeft, ChevronRight } from 'lucide-react';

const DAYS = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];

const shifts = {
  2: { label: '09:00–17:00', type: 'day' },
  3: { label: '09:00–17:00', type: 'day' },
  4: { label: '09:00–17:00', type: 'day' },
  5: { label: '09:00–17:00', type: 'day' },
  6: { label: '09:00–17:00', type: 'day' },
  9: { label: '09:00–17:00', type: 'day' },
  10: { label: '09:00–17:00', type: 'day' },
  11: { label: '14:00–22:00', type: 'late' },
  12: { label: '09:00–17:00', type: 'day' },
  13: { label: '09:00–17:00', type: 'day' },
  16: { label: 'Day Off', type: 'off' },
  17: { label: '09:00–17:00', type: 'day' },
  18: { label: '09:00–17:00', type: 'day' },
  19: { label: '09:00–17:00', type: 'day' },
  20: { label: '09:00–17:00', type: 'day' },
};

const typeColors = {
  day:  'bg-dash-primary/10 text-dash-primary',
  late: 'bg-amber-400/10 text-amber-400',
  off:  'bg-red-400/10 text-red-400',
};

function buildCalendarDays(year, month) {
  const firstDay = new Date(year, month, 1).getDay();
  const daysInMonth = new Date(year, month + 1, 0).getDate();
  const cells = [];
  for (let i = 0; i < firstDay; i++) cells.push(null);
  for (let d = 1; d <= daysInMonth; d++) cells.push(d);
  return cells;
}

export default function SchedulePage() {
  const now = new Date();
  const [year, setYear] = React.useState(now.getFullYear());
  const [month, setMonth] = React.useState(now.getMonth());

  const cells = buildCalendarDays(year, month);
  const today = now.getDate();
  const isCurrentMonth = year === now.getFullYear() && month === now.getMonth();

  function prev() {
    if (month === 0) { setMonth(11); setYear((y) => y - 1); }
    else setMonth((m) => m - 1);
  }
  function next() {
    if (month === 11) { setMonth(0); setYear((y) => y + 1); }
    else setMonth((m) => m + 1);
  }

  const monthLabel = new Date(year, month).toLocaleDateString('en-US', { month: 'long', year: 'numeric' });

  return (
    <div className="flex flex-col min-h-full bg-dash-bg">
      <TopNav title="Schedule" />
      <main className="p-6 space-y-6">

        {/* Calendar header */}
        <div className="bg-dash-card border border-dash-border rounded-xl overflow-hidden">
          <div className="flex items-center justify-between px-5 py-4 border-b border-dash-border">
            <h3 className="text-dash-text" style={{ fontSize: '14px', fontWeight: 600 }}>{monthLabel}</h3>
            <div className="flex gap-1">
              <button onClick={prev} className="w-8 h-8 flex items-center justify-center rounded-md text-dash-text-secondary hover:bg-dash-sidebar-hover transition-colors">
                <ChevronLeft size={16} />
              </button>
              <button onClick={next} className="w-8 h-8 flex items-center justify-center rounded-md text-dash-text-secondary hover:bg-dash-sidebar-hover transition-colors">
                <ChevronRight size={16} />
              </button>
            </div>
          </div>

          {/* Day headers */}
          <div className="grid grid-cols-7 border-b border-dash-border">
            {DAYS.map((d) => (
              <div key={d} className="py-2 text-center text-dash-text-muted" style={{ fontSize: '11px', fontWeight: 600, textTransform: 'uppercase' }}>
                {d}
              </div>
            ))}
          </div>

          {/* Cells */}
          <div className="grid grid-cols-7">
            {cells.map((day, i) => {
              const shift = day ? shifts[day] : null;
              const isToday = isCurrentMonth && day === today;
              return (
                <div
                  key={i}
                  className={`min-h-[80px] p-2 border-b border-r border-dash-border ${!day ? 'opacity-0 pointer-events-none' : ''}`}
                >
                  {day && (
                    <>
                      <span
                        className={`inline-flex w-6 h-6 items-center justify-center rounded-full ${
                          isToday ? 'bg-dash-primary text-white' : 'text-dash-text-secondary'
                        }`}
                        style={{ fontSize: '12px', fontWeight: isToday ? 700 : 400 }}
                      >
                        {day}
                      </span>
                      {shift && (
                        <div className={`mt-1 px-1.5 py-0.5 rounded text-center ${typeColors[shift.type]}`} style={{ fontSize: '10px', fontWeight: 500 }}>
                          {shift.label}
                        </div>
                      )}
                    </>
                  )}
                </div>
              );
            })}
          </div>
        </div>

        {/* Legend */}
        <div className="flex gap-4">
          {Object.entries(typeColors).map(([type, cls]) => (
            <div key={type} className="flex items-center gap-2">
              <span className={`px-2 py-0.5 rounded text-xs font-medium ${cls}`}>{type === 'day' ? 'Day shift' : type === 'late' ? 'Late shift' : 'Day off'}</span>
            </div>
          ))}
        </div>

      </main>
    </div>
  );
}
